import React, { useState } from 'react';
import '../styles/ProgramAvatar.css';

// --- Placeholder Data (swap with real images later) ---
const faceOptions = [
  { id: 1, label: 'Round',    color: '#F4C2C2', shape: 'round' },
  { id: 2, label: 'Oval',     color: '#F9D5A7', shape: 'oval' },
  { id: 3, label: 'Sharp',    color: '#C8E6C9', shape: 'sharp' },
  { id: 4, label: 'Soft',     color: '#BBDEFB', shape: 'soft' },
  { id: 5, label: 'Heart',    color: '#E1BEE7', shape: 'heart' },
  { id: 6, label: 'Square',   color: '#FFE0B2', shape: 'square' },
];

const hairOptions = [
  { id: 1, label: 'Short',    gradient: ['#8B4513', '#D2691E'] },
  { id: 2, label: 'Long',     gradient: ['#2C1810', '#5C3317'] },
  { id: 3, label: 'Wavy',     gradient: ['#DAA520', '#FFD700'] },
  { id: 4, label: 'Curly',    gradient: ['#1C1C1C', '#4A4A4A'] },
  { id: 5, label: 'Ponytail', gradient: ['#C0392B', '#E74C3C'] },
  { id: 6, label: 'Bun',      gradient: ['#8E44AD', '#9B59B6'] },
];

const skinOptions = [
  { id: 1, label: 'Fair',     color: '#FFDAB9' },
  { id: 2, label: 'Light',    color: '#F5CBA7' },
  { id: 3, label: 'Medium',   color: '#E59866' },
  { id: 4, label: 'Tan',      color: '#CA8A5A' },
  { id: 5, label: 'Brown',    color: '#A0522D' },
  { id: 6, label: 'Deep',     color: '#6B3A2A' },
];

const hairColorOptions = [
  { id: 1, label: 'Black',    color: '#1C1C1C' },
  { id: 2, label: 'Brown',    color: '#8B4513' },
  { id: 3, label: 'Blonde',   color: '#FFD700' },
  { id: 4, label: 'Red',      color: '#C0392B' },
  { id: 5, label: 'Purple',   color: '#8E44AD' },
  { id: 6, label: 'Blue',     color: '#2980B9' },
  { id: 7, label: 'Pink',     color: '#FF69B4' },
  { id: 8, label: 'White',    color: '#ECEFF1' },
];

const TABS = ['Face', 'Hair', 'Skin', 'Hair Color'];

// --- SVG Avatar Preview ---
const AvatarPreview = ({ selections }) => {
  const skinColor = skinOptions.find(s => s.id === selections.skin)?.color || '#FFDAB9';
  const hairColor = hairColorOptions.find(h => h.id === selections.hairColor)?.color || '#8B4513';
  const faceShape = faceOptions.find(f => f.id === selections.face)?.shape || 'round';
  const hairStyle = hairOptions.find(h => h.id === selections.hair)?.label || 'Short';

  // Face shape rx/ry adjustments
  const faceProps = {
    round:  { rx: 60, ry: 60 },
    oval:   { rx: 50, ry: 65 },
    sharp:  { rx: 45, ry: 60 },
    soft:   { rx: 58, ry: 62 },
    heart:  { rx: 55, ry: 58 },
    square: { rx: 30, ry: 30 },
  };
  const { rx, ry } = faceProps[faceShape] || faceProps.round;

  // Hair style paths
  const hairPaths = {
    Short:    <ellipse cx="120" cy="85" rx="62" ry="30" fill={hairColor} />,
    Long:     <><ellipse cx="120" cy="85" rx="62" ry="30" fill={hairColor} /><rect x="58" y="100" width="18" height="100" rx="9" fill={hairColor} /><rect x="164" y="100" width="18" height="100" rx="9" fill={hairColor} /></>,
    Wavy:     <><ellipse cx="120" cy="85" rx="62" ry="30" fill={hairColor} /><path d="M58 110 Q50 140 60 160 Q50 180 62 200" stroke={hairColor} strokeWidth="16" fill="none" strokeLinecap="round"/><path d="M182 110 Q190 140 180 160 Q190 180 178 200" stroke={hairColor} strokeWidth="16" fill="none" strokeLinecap="round"/></>,
    Curly:    <><ellipse cx="120" cy="85" rx="65" ry="32" fill={hairColor} /><circle cx="68" cy="115" r="16" fill={hairColor} /><circle cx="172" cy="115" r="16" fill={hairColor} /></>,
    Ponytail: <><ellipse cx="120" cy="85" rx="62" ry="30" fill={hairColor} /><ellipse cx="182" cy="130" rx="12" ry="40" fill={hairColor} /></>,
    Bun:      <><ellipse cx="120" cy="85" rx="62" ry="30" fill={hairColor} /><circle cx="120" cy="62" r="22" fill={hairColor} /></>,
  };

  return (
    <svg viewBox="0 0 240 280" width="220" height="220" xmlns="http://www.w3.org/2000/svg">
      {/* Body */}
      <ellipse cx="120" cy="260" rx="70" ry="40" fill={skinColor} opacity="0.6" />
      {/* Neck */}
      <rect x="105" y="185" width="30" height="35" rx="10" fill={skinColor} />
      {/* Hair back */}
      {hairPaths[hairStyle] || hairPaths['Short']}
      {/* Face */}
      <ellipse cx="120" cy="145" rx={rx} ry={ry} fill={skinColor} />
      {/* Eyes */}
      <circle cx="100" cy="138" r="7" fill="white" />
      <circle cx="140" cy="138" r="7" fill="white" />
      <circle cx="101" cy="139" r="4" fill="#2C1810" />
      <circle cx="141" cy="139" r="4" fill="#2C1810" />
      <circle cx="103" cy="137" r="1.5" fill="white" />
      <circle cx="143" cy="137" r="1.5" fill="white" />
      {/* Nose */}
      <ellipse cx="120" cy="155" rx="5" ry="3" fill={skinColor} stroke="#D4A88A" strokeWidth="1" />
      {/* Mouth */}
      <path d="M108 168 Q120 176 132 168" stroke="#E87070" strokeWidth="2.5" fill="none" strokeLinecap="round" />
      {/* Cheeks */}
      <circle cx="90" cy="160" r="10" fill="#FFB6C1" opacity="0.4" />
      <circle cx="150" cy="160" r="10" fill="#FFB6C1" opacity="0.4" />
      {/* Hair front overlay */}
      <ellipse cx="120" cy="92" rx="60" ry="18" fill={hairColor} opacity="0.85" />
    </svg>
  );
};

// --- Option Card ---
const OptionCard = ({ option, isSelected, onSelect, type }) => {
  const getStyle = () => {
    if (type === 'hair') {
      return { background: `linear-gradient(135deg, ${option.gradient[0]}, ${option.gradient[1]})` };
    }
    return { background: option.color };
  };

  return (
    <div
      className={`option-card ${isSelected ? 'selected' : ''}`}
      onClick={() => onSelect(option.id)}
      data-testid={`${type}-option-${option.id}`}
    >
      <div className="option-circle" style={getStyle()} />
      <span className="option-label">{option.label}</span>
    </div>
  );
};

// --- Main Component ---
const ProgramAvatar = () => {
  const [avatarName, setAvatarName] = useState('');
  const [activeTab, setActiveTab] = useState('Face');
  const [selections, setSelections] = useState({
    face: 1,
    hair: 1,
    skin: 1,
    hairColor: 1,
  });
  const [created, setCreated] = useState(false);

  const handleSelect = (type, id) => {
    setSelections(prev => ({ ...prev, [type]: id }));
  };

  const renderOptions = () => {
    switch (activeTab) {
      case 'Face':
        return faceOptions.map(opt => (
          <OptionCard key={opt.id} option={opt} type="face"
            isSelected={selections.face === opt.id}
            onSelect={(id) => handleSelect('face', id)} />
        ));
      case 'Hair':
        return hairOptions.map(opt => (
          <OptionCard key={opt.id} option={opt} type="hair"
            isSelected={selections.hair === opt.id}
            onSelect={(id) => handleSelect('hair', id)} />
        ));
      case 'Skin':
        return skinOptions.map(opt => (
          <OptionCard key={opt.id} option={opt} type="skin"
            isSelected={selections.skin === opt.id}
            onSelect={(id) => handleSelect('skin', id)} />
        ));
      case 'Hair Color':
        return hairColorOptions.map(opt => (
          <OptionCard key={opt.id} option={opt} type="hairColor"
            isSelected={selections.hairColor === opt.id}
            onSelect={(id) => handleSelect('hairColor', id)} />
        ));
      default:
        return null;
    }
  };

  return (
    <div className="page-container">
      <div className="avatar-page-layout">

        {/* Left — Avatar Preview */}
        <div className="card avatar-preview-card" data-testid="avatar-main">
          <h2 className="section-title">Your Avatar</h2>
          <div className="avatar-display">
            <div className="avatar-svg-wrapper" data-testid="avatar-preview">
              <AvatarPreview selections={selections} />
            </div>
            <input
              type="text"
              placeholder="Enter your Avatar name......"
              value={avatarName}
              onChange={(e) => setAvatarName(e.target.value)}
              className="avatar-name-input"
              data-testid="avatar-name-input"
            />
            {created && avatarName && (
              <div className="avatar-created-badge">✅ {avatarName} created!</div>
            )}
          </div>
        </div>

        {/* Right — Tabs + Options */}
        <div className="card avatar-options-card">
          <h2 className="section-title">Customize</h2>

          {/* Tabs */}
          <div className="avatar-tabs">
            {TABS.map(tab => (
              <button
                key={tab}
                className={`avatar-tab ${activeTab === tab ? 'active' : ''}`}
                onClick={() => setActiveTab(tab)}
              >
                {tab}
              </button>
            ))}
          </div>

          {/* Options Grid */}
          <div className="options-grid">
            {renderOptions()}
          </div>

          {/* Create Button */}
          <button
            className="create-button"
            data-testid="avatar-create-btn"
            onClick={() => setCreated(true)}
          >
            CREATE AVATAR
          </button>
        </div>

      </div>
    </div>
  );
};

export default ProgramAvatar;
